{
  "grammar": [
    {
      "pattern": "曾經 + Verb + 過",
      "structure": ["曾經", "Verb", "過"],
      "explanation_en": "Used to express that someone has experienced something in the past. It emphasizes the experience itself, not the specific time.",
      "title": "Past Experience with 曾經...過",
      "meaning": "Have done something before",
      "when_to_use": [
        "When asking or talking about past experiences",
        "When emphasizing that something happened at least once before"
      ],
      "when_not_to_use": [
        "Do not use for actions that happened at a specific time (use 了 instead)",
        "Do not use for actions that are still ongoing"
      ],
      "pragmatic_notes": "In Taiwan, 曾經 is more formal than 有...過. In casual conversation, people often drop 曾經 and just use Verb + 過.",
      "word_order_notes": "曾經 comes before the verb, and 過 comes after the verb. The object can come after 過 or before the verb.",
      "english_contrast": "English uses 'have/has + past participle' (e.g., 'I have eaten that before'). Chinese uses 曾經...過.",
      "korean_contrast": "Korean uses '-(어)본 적이 있다' (e.g., '먹어본 적이 있어요'). Chinese 曾經...過 is similar.",
      "negative_examples": [
        {
          "text": "我曾經吃過飯。",
          "error": "This sentence is grammatically correct but pragmatically odd because 吃飯 is a daily routine, not a notable experience."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我曾經昨天去過公園。",
          "error": "Cannot use 曾經 with a specific time like 昨天. Use 了 instead."
        }
      ],
      "transformation_drills": [
        "Change '我吃過台灣小吃。' to use 曾經.",
        "Change '他曾經去過日本。' to a negative sentence."
      ],
      "production_drills": [
        "Tell your friend about a food you have tried before using 曾經...過.",
        "Ask your classmate if they have ever been to Taipei 101."
      ],
      "common_error_patterns": [
        "Using 曾經 with specific time words",
        "Forgetting 過 after the verb"
      ],
      "repair_feedback": {
        "word_order": "Remember: 曾經 + Verb + 過. Do not put 過 before the verb.",
        "politeness": "Using 曾經 is polite and formal. In casual speech, you can just use Verb + 過.",
        "vocabulary": "Use 曾經 for notable experiences, not for daily routines."
      }
    },
    {
      "pattern": "正在 + Verb",
      "structure": ["正在", "Verb"],
      "explanation_en": "Used to describe an action that is currently in progress at the moment of speaking.",
      "title": "Ongoing Action with 正在",
      "meaning": "Is doing something right now",
      "when_to_use": [
        "When describing what someone is doing at this moment",
        "When answering 'What are you doing?'"
      ],
      "when_not_to_use": [
        "Do not use for habitual actions (use 每天 or 常常 instead)",
        "Do not use for future plans (use 要 or 打算 instead)"
      ],
      "pragmatic_notes": "In Taiwan, 正在 is more formal. In casual conversation, people often just use 在 alone (e.g., 我在吃飯).",
      "word_order_notes": "正在 comes before the verb. The object comes after the verb.",
      "english_contrast": "English uses 'am/is/are + verb-ing' (e.g., 'I am eating'). Chinese uses 正在 + Verb.",
      "korean_contrast": "Korean uses '~고 있다' (e.g., '먹고 있어요'). Chinese 正在 is similar.",
      "negative_examples": [
        {
          "text": "我每天正在吃飯。",
          "error": "Cannot use 正在 with habitual actions. Use 每天 instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我明天正在去台北。",
          "error": "Cannot use 正在 for future plans. Use 要 or 打算 instead."
        }
      ],
      "transformation_drills": [
        "Change '我吃飯。' to show ongoing action.",
        "Change '他正在看書。' to a negative sentence."
      ],
      "production_drills": [
        "Tell your friend what you are doing right now using 正在.",
        "Ask your classmate what they are doing at this moment."
      ],
      "common_error_patterns": [
        "Using 正在 for habitual or future actions",
        "Forgetting the verb after 正在"
      ],
      "repair_feedback": {
        "word_order": "Remember: 正在 + Verb. Do not put the object before the verb.",
        "politeness": "Using 正在 is polite. In casual speech, 在 is more common.",
        "vocabulary": "Use 正在 for actions happening right now, not for routines or plans."
      }
    },
    {
      "pattern": "能夠 + Verb",
      "structure": ["能夠", "Verb"],
      "explanation_en": "Used to express ability or capability to do something, often implying that the ability is acquired or that conditions allow it.",
      "title": "Ability with 能夠",
      "meaning": "Can / be able to",
      "when_to_use": [
        "When talking about ability that requires effort or conditions",
        "When emphasizing that someone has the capability to do something"
      ],
      "when_not_to_use": [
        "Do not use for simple physical ability (use 會 instead)",
        "Do not use for permission (use 可以 instead)"
      ],
      "pragmatic_notes": "In Taiwan, 能夠 is more formal than 會 or 可以. It is often used in written or formal speech.",
      "word_order_notes": "能夠 comes before the verb. The object comes after the verb.",
      "english_contrast": "English uses 'can' or 'be able to' (e.g., 'I can speak Chinese'). Chinese uses 能夠 for ability with conditions.",
      "korean_contrast": "Korean uses '~ㄹ 수 있다' (e.g., '할 수 있어요'). Chinese 能夠 is similar.",
      "negative_examples": [
        {
          "text": "我能夠喝水。",
          "error": "This is grammatically correct but pragmatically odd because 喝水 is a simple action that does not require special ability."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我能夠去廁所嗎？",
          "error": "Cannot use 能夠 for permission. Use 可以 instead."
        }
      ],
      "transformation_drills": [
        "Change '我會說中文。' to use 能夠.",
        "Change '他能夠游泳。' to a negative sentence."
      ],
      "production_drills": [
        "Tell your friend about a skill you have using 能夠.",
        "Ask your classmate if they are able to come to the party."
      ],
      "common_error_patterns": [
        "Using 能夠 for simple physical abilities",
        "Using 能夠 for permission"
      ],
      "repair_feedback": {
        "word_order": "Remember: 能夠 + Verb. Do not put the object before the verb.",
        "politeness": "Using 能夠 is formal. In casual speech, 會 or 可以 is more common.",
        "vocabulary": "Use 能夠 for abilities that require effort or conditions, not for simple actions."
      }
    }
  ]
}
